using Microsoft.EntityFrameworkCore;

class ProductContext : DbContext
{
    public DbSet<Product> Products => Set<Product>();

    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Product>(b =>
        {
            b.ToContainer("Products");
            b.HasIndex(p => p.Sku);

            // BREAKING CHANGE 1 — Discriminator property renamed.
            // EF Core 9 writes "$type" instead of "Discriminator".
            // Existing documents and raw SQL queries (c.Discriminator) rely on the old name.
            b.HasDiscriminator<string>("Discriminator");

            // BREAKING CHANGE 2 — Resource-id format changed.
            // EF Core 8: id = "Product|{key}"   EF Core 9: id = "{key}".
            // Existing 500K documents use the old format; preserve it via a value conversion.
            b.Property(p => p.Id)
                .HasConversion(
                    id => $"Product|{id}",
                    cosmosId => int.Parse(
                        cosmosId.Substring(cosmosId.IndexOf('|') + 1)));
        });
    }
}

class Product { public int Id { get; set; } public string Sku { get; set; } }

