using Microsoft.EntityFrameworkCore;

class CosmosQuery
{
    // BREAKING CHANGE 3 — Synchronous I/O removed.
    // The EF Core 9 Cosmos provider throws InvalidOperationException on sync calls.
    // All queries must use async methods.
    async Task FindProductsAsync(ProductContext ctx)
    {
        // Raw SQL is safe — our HasDiscriminator("Discriminator") config keeps the old
        // property name, so c.Discriminator still resolves against existing documents.
        var sql = "SELECT * FROM c WHERE c.Discriminator = 'Product' AND c.Sku = @sku";

        var products = await ctx.Products.Where(p => p.Sku == "ABC").ToListAsync();
    }
}

